1	import {
2		Controller,
3		Headers,
4		HttpCode,
5		HttpStatus,
6		Post,
7		Req,
8		UnauthorizedException,
9	} from '@nestjs/common';
10	import { ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';
11	
12	import { Public } from '@modules/auth/decorators/public.decorator';
13	import { GithubWebhookService } from '@modules/github/github-webhook.service';
14	
15	import { LogExecution } from '@decorators/log-execution.decorator';
16	
17	import type { FastifyRequest } from 'fastify';
18	
19	@ApiTags('GitHub Webhooks')
20	@Controller('integrations/github')
21	export class GithubWebhookController {
22		constructor(private readonly githubWebhookService: GithubWebhookService) {}
23	
24		@Post('webhook')
25		@Public()
26		@HttpCode(HttpStatus.OK)
27		@ApiOperation({ summary: 'Receive GitHub App webhook events' })
28		@ApiResponse({ status: HttpStatus.OK, description: 'Event received' })
29		@ApiResponse({ status: HttpStatus.UNAUTHORIZED, description: 'Invalid signature' })
30		@LogExecution()
31		async handleWebhook(
32			@Req() request: FastifyRequest & { rawBody?: string },
33			@Headers() headers: Record<string, string>,
34		): Promise<void> {
35			const rawBody = request.rawBody ?? '';
36			const signature = headers['x-hub-signature-256'] ?? '';
37			const event = headers['x-github-event'] ?? '';
38			const installationIdRaw = headers['x-github-hook-installation-target-id'] ?? '0';
39	
40			const isValid = this.githubWebhookService.verifySignature({
41				payload: rawBody,
42				signature,
43			});
44	
45			if (!isValid) {
46				throw new UnauthorizedException('Invalid webhook signature');
47			}
48	
49			const payload = JSON.parse(rawBody) as { installation?: { id?: number } };
50			const installationId = payload?.installation?.id ?? Number(installationIdRaw);
51	
52			await this.githubWebhookService.handleEvent({
53				event,
54				installationId,
55				payload,
56			});
57		}
58	}
