1	import { HttpService } from '@nestjs/axios';
2	import { Processor, WorkerHost } from '@nestjs/bullmq';
3	import { Logger } from '@nestjs/common';
4	import { Job } from 'bullmq';
5	
6	import { GithubCommitModel } from '@modules/github/db/github-commit.model';
7	import { GithubContributorModel } from '@modules/github/db/github-contributor.model';
8	import { GithubInstallationModel } from '@modules/github/db/github-installations.model';
9	import { GithubPullRequestModel } from '@modules/github/db/github-pull-request.model';
10	import { GithubRepoModel } from '@modules/github/db/github-repos.model';
11	import { GithubReviewCommentModel } from '@modules/github/db/github-review-comment.model';
12	import { GithubReviewModel } from '@modules/github/db/github-review.model';
13	import { GithubAppService } from '@modules/github/github-app.service';
14	import {
15		IGithubApiCommit,
16		IGithubApiPullRequest,
17		IGithubApiReview,
18		IGithubApiReviewComment,
19		IGithubInstallationRepositoriesEvent,
20		IGithubWebhookPREvent,
21		IGithubWebhookPushEvent,
22		IGithubWebhookReviewCommentEvent,
23		IGithubWebhookReviewEvent,
24	} from '@modules/github/types/github-api.interface';
25	import { IGithubCommitUpsert } from '@modules/github/types/github-commit.interface';
26	import { GithubPRState } from '@modules/github/types/github-pull-request.interface';
27	import { GithubReviewState } from '@modules/github/types/github-review.interface';
28	
29	interface IRawEventJob {
30		event: string;
31		installationId: number;
32		payload: unknown;
33		receivedAt: Date;
34	}
35	
36	interface IBackfillRepoJob {
37		installationDbId: string;
38		installationId: number;
39		repoDbId: string;
40		repoFullName: string;
41	}
42	
43	@Processor('github')
44	export class GithubEventProcessor extends WorkerHost {
45		private readonly logger = new Logger(GithubEventProcessor.name);
46	
47		constructor(
48			private readonly installationModel: GithubInstallationModel,
49			private readonly repoModel: GithubRepoModel,
50			private readonly contributorModel: GithubContributorModel,
51			private readonly commitModel: GithubCommitModel,
52			private readonly pullRequestModel: GithubPullRequestModel,
53			private readonly reviewModel: GithubReviewModel,
54			private readonly reviewCommentModel: GithubReviewCommentModel,
55			private readonly githubAppService: GithubAppService,
56			private readonly httpService: HttpService,
57		) {
58			super();
59		}
60	
61		async process(job: Job<IRawEventJob>): Promise<void> {
62			if (job.name === 'backfill_repo') {
63				await this.handleBackfillRepo({ data: job.data as unknown as IBackfillRepoJob });
64				return;
65			}
66			if (job.name !== 'raw_event') return;
67	
68			const { event, installationId, payload } = job.data;
69	
70			try {
71				const installation = await this.installationModel.findByInstallationId({
72					installationId,
73				});
74	
75				if (!installation) {
76					this.logger.warn(`No installation found for installationId: ${installationId}`);
77					return;
78				}
79	
80				switch (event) {
81					case 'push':
82						await this.handlePush({
83							installationDbId: installation._id,
84							payload: payload as IGithubWebhookPushEvent,
85						});
86						break;
87					case 'pull_request':
88						await this.handlePullRequest({
89							installationDbId: installation._id,
90							payload: payload as IGithubWebhookPREvent,
91						});
92						break;
93					case 'pull_request_review':
94						await this.handleReview({
95							installationDbId: installation._id,
96							payload: payload as IGithubWebhookReviewEvent,
97						});
98						break;
99					case 'pull_request_review_comment':
100						await this.handleReviewComment({
101							installationDbId: installation._id,
102							payload: payload as IGithubWebhookReviewCommentEvent,
103						});
104						break;
105					case 'installation_repositories':
106						await this.handleInstallationRepositories({
107							installationDbId: installation._id,
108							payload: payload as IGithubInstallationRepositoriesEvent,
109						});
110						break;
111					default:
112						this.logger.debug(`Unhandled event type: ${event}`);
113				}
114			} catch (error) {
115				this.logger.error(
116					`Failed to process ${event} event for installation ${installationId}: ${(error as Error).message}`,
117				);
118				throw error;
119			}
120		}
121	
122		private async handlePush({
123			installationDbId,
124			payload,
125		}: {
126			installationDbId: string;
127			payload: IGithubWebhookPushEvent;
128		}): Promise<void> {
129			const repo = await this.repoModel.findByGithubRepoId({
130				githubRepoId: payload.repository.id,
131			});
132	
133			if (!repo) {
134				this.logger.warn(`Repo not found for github_repo_id: ${payload.repository.id}`);
135				return;
136			}
137	
138			const distinctCommits = payload.commits.filter((c) => c.distinct);
139	
140			if (distinctCommits.length === 0) return;
141	
142			for (const commit of distinctCommits) {
143				if (commit.author.username) {
144					await this.contributorModel.upsert({
145						data: {
146							installation_id: installationDbId,
147							github_user_id: 0,
148							github_login: commit.author.username,
149							github_name: commit.author.name,
150							github_email: commit.author.email,
151						},
152					});
153				}
154			}
155	
156			const commits: IGithubCommitUpsert[] = distinctCommits.map((c) => ({
157				installation_id: installationDbId,
158				repo_id: repo._id,
159				sha: c.id,
160				message: c.message,
161				author_login: c.author.username ?? null,
162				author_name: c.author.name,
163				author_email: c.author.email,
164				committed_at: new Date(c.timestamp),
165				additions: 0,
166				deletions: 0,
167				is_merge_commit: (c.parents?.length ?? 0) > 1,
168			}));
169	
170			await this.commitModel.upsertMany({ commits });
171		}
172	
173		private async handlePullRequest({
174			installationDbId,
175			payload,
176		}: {
177			installationDbId: string;
178			payload: IGithubWebhookPREvent;
179		}): Promise<void> {
180			const repo = await this.repoModel.findByGithubRepoId({
181				githubRepoId: payload.repository.id,
182			});
183	
184			if (!repo) {
185				this.logger.warn(`Repo not found for github_repo_id: ${payload.repository.id}`);
186				return;
187			}
188	
189			const pr = payload.pull_request;
190	
191			await this.contributorModel.upsert({
192				data: {
193					installation_id: installationDbId,
194					github_user_id: pr.user.id,
195					github_login: pr.user.login,
196				},
197			});
198	
199			await this.pullRequestModel.upsert({
200				data: {
201					installation_id: installationDbId,
202					repo_id: repo._id,
203					github_pr_id: pr.id,
204					pr_number: pr.number,
205					title: pr.title,
206					state: pr.state as GithubPRState,
207					author_login: pr.user.login,
208					draft: pr.draft,
209					merged: pr.merged,
210					additions: pr.additions,
211					deletions: pr.deletions,
212					changed_files: pr.changed_files,
213					commits_count: pr.commits,
214					opened_at: new Date(pr.created_at),
215					merged_at: pr.merged_at ? new Date(pr.merged_at) : null,
216					closed_at: pr.closed_at ? new Date(pr.closed_at) : null,
217				},
218			});
219		}
220	
221		private async handleReview({
222			installationDbId,
223			payload,
224		}: {
225			installationDbId: string;
226			payload: IGithubWebhookReviewEvent;
227		}): Promise<void> {
228			const repo = await this.repoModel.findByGithubRepoId({
229				githubRepoId: payload.repository.id,
230			});
231	
232			if (!repo) return;
233	
234			const pullRequest = await this.pullRequestModel.findByRepoAndNumber({
235				repoId: repo._id,
236				prNumber: payload.pull_request.number,
237			});
238	
239			if (!pullRequest) {
240				this.logger.warn(
241					`Pull request #${payload.pull_request.number} not found for repo ${repo._id}`,
242				);
243				return;
244			}
245	
246			const normalizedState = payload.review.state.toLowerCase();
247			const validStates: string[] = [
248				GithubReviewState.APPROVED,
249				GithubReviewState.CHANGES_REQUESTED,
250				GithubReviewState.COMMENTED,
251				GithubReviewState.DISMISSED,
252			];
253	
254			if (!validStates.includes(normalizedState)) return;
255	
256			await this.contributorModel.upsert({
257				data: {
258					installation_id: installationDbId,
259					github_user_id: payload.review.user.id,
260					github_login: payload.review.user.login,
261				},
262			});
263	
264			await this.reviewModel.upsert({
265				data: {
266					installation_id: installationDbId,
267					pull_request_id: pullRequest._id,
268					github_review_id: payload.review.id,
269					reviewer_login: payload.review.user.login,
270					state: normalizedState as GithubReviewState,
271					submitted_at: new Date(payload.review.submitted_at),
272				},
273			});
274		}
275	
276		private async handleReviewComment({
277			installationDbId,
278			payload,
279		}: {
280			installationDbId: string;
281			payload: IGithubWebhookReviewCommentEvent;
282		}): Promise<void> {
283			if (payload.action === 'deleted') return;
284	
285			const repo = await this.repoModel.findByGithubRepoId({
286				githubRepoId: payload.repository.id,
287			});
288	
289			if (!repo) return;
290	
291			const pullRequest = await this.pullRequestModel.findByRepoAndNumber({
292				repoId: repo._id,
293				prNumber: payload.pull_request.number,
294			});
295	
296			if (!pullRequest) {
297				this.logger.warn(
298					`Pull request #${payload.pull_request.number} not found for repo ${repo._id}`,
299				);
300				return;
301			}
302	
303			await this.contributorModel.upsert({
304				data: {
305					installation_id: installationDbId,
306					github_user_id: payload.comment.user.id,
307					github_login: payload.comment.user.login,
308				},
309			});
310	
311			await this.reviewCommentModel.upsert({
312				data: {
313					installation_id: installationDbId,
314					pull_request_id: pullRequest._id,
315					github_comment_id: payload.comment.id,
316					author_login: payload.comment.user.login,
317					body: payload.comment.body,
318					path: payload.comment.path,
319					line: payload.comment.line,
320					commented_at: new Date(payload.comment.created_at),
321				},
322			});
323		}
324	
325		private async handleInstallationRepositories({
326			installationDbId,
327			payload,
328		}: {
329			installationDbId: string;
330			payload: IGithubInstallationRepositoriesEvent;
331		}): Promise<void> {
332			if ((payload.repositories_added?.length ?? 0) > 0) {
333				await this.repoModel.upsertMany({
334					installationId: installationDbId,
335					repos: payload.repositories_added,
336				});
337			}
338	
339			if ((payload.repositories_removed?.length ?? 0) > 0) {
340				await this.repoModel.removeByGithubIds({
341					installationId: installationDbId,
342					githubRepoIds: payload.repositories_removed.map((r) => r.id),
343				});
344			}
345		}
346	
347		private async handleBackfillRepo({ data }: { data: IBackfillRepoJob }): Promise<void> {
348			const { installationDbId, installationId, repoDbId, repoFullName } = data;
349			this.logger.debug(`Starting backfill for repo ${repoFullName}`);
350			const token = await this.githubAppService.getInstallationToken({ installationId });
351			const parts = repoFullName.split('/');
352			const owner = parts[0] ?? '';
353			const repo = parts[1] ?? '';
354			await this.backfillCommits({
355				installationDbId,
356				repoDbId,
357				repoFullName,
358				owner,
359				repo,
360				token,
361			});
362			await this.backfillPullRequests({
363				installationDbId,
364				repoDbId,
365				repoFullName,
366				owner,
367				repo,
368				token,
369			});
370			this.logger.debug(`Backfill complete for repo ${repoFullName}`);
371		}
372	
373		private async backfillCommits({
374			installationDbId,
375			repoDbId,
376			repoFullName,
377			owner,
378			repo,
379			token,
380		}: {
381			installationDbId: string;
382			repoDbId: string;
383			repoFullName: string;
384			owner: string;
385			repo: string;
386			token: string;
387		}): Promise<void> {
388			let page = 1;
389			const perPage = 100;
390			while (true) {
391				const { data: commits } = await this.httpService.axiosRef.get<IGithubApiCommit[]>(
392					`https://api.github.com/repos/${owner}/${repo}/commits`,
393					{
394						headers: {
395							Authorization: `token ${token}`,
396							Accept: 'application/vnd.github+json',
397							'X-GitHub-Api-Version': '2022-11-28',
398						},
399						params: { per_page: perPage, page },
400					},
401				);
402				if (commits.length === 0) break;
403				await this.commitModel.upsertMany({
404					commits: commits.map((c) => ({
405						installation_id: installationDbId,
406						repo_id: repoDbId,
407						sha: c.sha,
408						message: c.commit.message,
409						author_login: c.author?.login ?? null,
410						author_name: c.commit.author.name,
411						author_email: c.commit.author.email,
412						committed_at: new Date(c.commit.author.date),
413						additions: c.stats?.additions ?? 0,
414						deletions: c.stats?.deletions ?? 0,
415						is_merge_commit: c.parents.length > 1,
416					})),
417				});
418				if (commits.length < perPage) break;
419				page++;
420			}
421			this.logger.debug(`Backfilled commits for ${repoFullName}`);
422		}
423	
424		private async backfillPullRequests({
425			installationDbId,
426			repoDbId,
427			repoFullName,
428			owner,
429			repo,
430			token,
431		}: {
432			installationDbId: string;
433			repoDbId: string;
434			repoFullName: string;
435			owner: string;
436			repo: string;
437			token: string;
438		}): Promise<void> {
439			let page = 1;
440			const perPage = 100;
441			while (true) {
442				const { data: prs } = await this.httpService.axiosRef.get<IGithubApiPullRequest[]>(
443					`https://api.github.com/repos/${owner}/${repo}/pulls`,
444					{
445						headers: {
446							Authorization: `token ${token}`,
447							Accept: 'application/vnd.github+json',
448							'X-GitHub-Api-Version': '2022-11-28',
449						},
450						params: { state: 'all', per_page: perPage, page },
451					},
452				);
453				if (prs.length === 0) break;
454				for (const pr of prs) {
455					await this.contributorModel.upsert({
456						data: {
457							installation_id: installationDbId,
458							github_user_id: pr.user.id,
459							github_login: pr.user.login,
460						},
461					});
462					const saved = await this.pullRequestModel.upsert({
463						data: {
464							installation_id: installationDbId,
465							repo_id: repoDbId,
466							github_pr_id: pr.id,
467							pr_number: pr.number,
468							title: pr.title,
469							state: pr.state as GithubPRState,
470							author_login: pr.user.login,
471							draft: pr.draft,
472							merged: pr.merged,
473							additions: pr.additions,
474							deletions: pr.deletions,
475							changed_files: pr.changed_files,
476							commits_count: pr.commits,
477							opened_at: new Date(pr.created_at),
478							merged_at: pr.merged_at ? new Date(pr.merged_at) : null,
479							closed_at: pr.closed_at ? new Date(pr.closed_at) : null,
480						},
481					});
482					await this.backfillPrReviews({
483						installationDbId,
484						prDbId: saved._id,
485						owner,
486						repo,
487						prNumber: pr.number,
488						token,
489					});
490					await this.backfillPrReviewComments({
491						installationDbId,
492						prDbId: saved._id,
493						owner,
494						repo,
495						prNumber: pr.number,
496						token,
497					});
498				}
499				if (prs.length < perPage) break;
500				page++;
501			}
502			this.logger.debug(`Backfilled PRs for ${repoFullName}`);
503		}
504	
505		private async backfillPrReviews({
506			installationDbId,
507			prDbId,
508			owner,
509			repo,
510			prNumber,
511			token,
512		}: {
513			installationDbId: string;
