1	import { InjectQueue } from '@nestjs/bullmq';
2	import { Injectable, Logger } from '@nestjs/common';
3	import { Queue } from 'bullmq';
4	
5	import { JiraChangelogModel } from '@modules/jira/db/jira-changelog.model';
6	import { JiraInstallationModel } from '@modules/jira/db/jira-installations.model';
7	import { JiraIssueModel } from '@modules/jira/db/jira-issues.model';
8	import { JiraProjectModel } from '@modules/jira/db/jira-projects.model';
9	import { JiraSprintModel } from '@modules/jira/db/jira-sprints.model';
10	import { JiraWorklogModel } from '@modules/jira/db/jira-worklogs.model';
11	import { JiraApiService } from '@modules/jira/jira-api.service';
12	import { IJiraApiIssue } from '@modules/jira/types/jira-api.interface';
13	import { IJiraIssueBase } from '@modules/jira/types/jira-installation.interface';
14	
15	const THREE_YEARS_MS = 3 * 365 * 24 * 60 * 60 * 1000;
16	
17	@Injectable()
18	export class JiraSyncService {
19		private readonly logger = new Logger(JiraSyncService.name);
20	
21		constructor(
22			private readonly installationModel: JiraInstallationModel,
23			private readonly projectModel: JiraProjectModel,
24			private readonly issueModel: JiraIssueModel,
25			private readonly changelogModel: JiraChangelogModel,
26			private readonly worklogModel: JiraWorklogModel,
27			private readonly sprintModel: JiraSprintModel,
28			private readonly jiraApiService: JiraApiService,
29			@InjectQueue('jira') private readonly jiraQueue: Queue,
30		) {}
31	
32		async discoverProjects({
33			installationDbId,
34		}: {
35			installationDbId: string;
36		}): Promise<void> {
37			const installation = await this.installationModel.findById({ id: installationDbId });
38	
39			if (!installation) {
40				this.logger.warn(`Installation ${installationDbId} not found`);
41				return;
42			}
43	
44			const token = await this.jiraApiService.getValidToken({ installation });
45			const projects = await this.jiraApiService.listProjects({
46				cloudId: installation.cloud_id,
47				token,
48			});
49	
50			const savedProjects = await this.projectModel.upsertMany({
51				installationId: installationDbId,
52				projects,
53			});
54	
55			for (const project of savedProjects) {
56				await this.jiraQueue.add(
57					'sync_project',
58					{
59						installationDbId,
60						projectDbId: project._id,
61						projectKey: project.project_key,
62						projectId: project.project_id,
63					},
64					{ attempts: 3, backoff: { type: 'exponential', delay: 5000 } },
65				);
66			}
67	
68			this.logger.debug(
69				`Enqueued sync for ${savedProjects.length} projects in installation ${installationDbId}`,
70			);
71		}
72	
73		async syncProject({
74			installationDbId,
75			projectDbId,
76			projectKey,
77		}: {
78			installationDbId: string;
79			projectDbId: string;
80			projectKey: string;
81		}): Promise<void> {
82			const installation = await this.installationModel.findById({ id: installationDbId });
83	
84			if (!installation) {
85				this.logger.warn(`Installation ${installationDbId} not found`);
86				return;
87			}
88	
89			const projects = await this.projectModel.findByInstallationId({
90				installationId: installationDbId,
91			});
92			const project = projects.find((p) => p._id === projectDbId);
93	
94			if (!project) {
95				this.logger.warn(`Project ${projectDbId} not found`);
96				return;
97			}
98	
99			const token = await this.jiraApiService.getValidToken({ installation });
100	
101			const since = project.last_synced_at ?? new Date(Date.now() - THREE_YEARS_MS);
102	
103			const sinceStr = since.toISOString().split('T')[0] ?? since.toISOString();
104			const jql = `project = "${projectKey}" AND updated >= "${sinceStr}" ORDER BY updated ASC`;
105	
106			await this.fetchAndStoreIssues({
107				installationDbId,
108				projectDbId,
109				cloudId: installation.cloud_id,
110				token,
111				jql,
112			});
113	
114			await this.fetchAndStoreSprints({
115				installationDbId,
116				projectKey,
117				cloudId: installation.cloud_id,
118				token,
119			});
120	
121			await this.projectModel.updateLastSyncedAt({ id: projectDbId });
122	
123			this.logger.debug(
124				`Sync complete for project ${projectKey} in installation ${installationDbId}`,
125			);
126		}
127	
128		async pollAllInstallations(): Promise<void> {
129			const installations = await this.installationModel.findAllActive();
130	
131			for (const installation of installations) {
132				await this.jiraQueue.add(
133					'discover_projects',
134					{ installationDbId: installation._id },
135					{ attempts: 3, backoff: { type: 'exponential', delay: 5000 } },
136				);
137			}
138	
139			this.logger.debug(
140				`Triggered discover_projects for ${installations.length} active installations`,
141			);
142		}
143	
144		private async fetchAndStoreIssues({
145			installationDbId,
146			projectDbId,
147			cloudId,
148			token,
149			jql,
150		}: {
151			installationDbId: string;
152			projectDbId: string;
153			cloudId: string;
154			token: string;
155			jql: string;
156		}): Promise<void> {
157			let nextPageToken: string | undefined;
158	
159			while (true) {
160				const response = await this.jiraApiService.searchIssues({
161					cloudId,
162					token,
163					jql,
164					...(nextPageToken !== undefined && { nextPageToken }),
165				});
166	
167				if (response.issues.length === 0) break;
168	
169				const savedIssues = await this.issueModel.upsertMany({
170					issues: response.issues.map((issue) => ({
171						installation_id: installationDbId,
172						project_id: projectDbId,
173						issue_key: issue.key,
174						issue_id: issue.id,
175						issue_type: issue.fields.issuetype?.name ?? null,
176						status: issue.fields.status?.name ?? null,
177						priority: issue.fields.priority?.name ?? null,
178						assignee_id: issue.fields.assignee?.accountId ?? null,
179						reporter_id: issue.fields.reporter?.accountId ?? null,
180						story_points: issue.fields.customfield_10016 ?? null,
181						updated_at: new Date(issue.fields.updated),
182						resolved_at: issue.fields.resolutiondate
183							? new Date(issue.fields.resolutiondate)
184							: null,
185					})),
186				});
187	
188				await this.storeChangelogs({
189					installationDbId,
190					issues: response.issues,
191					savedIssues,
192				});
193	
194				await this.storeWorklogs({
195					installationDbId,
196					cloudId,
197					token,
198					issues: response.issues,
199					savedIssues,
200				});
201	
202				if (response.isLast || !response.nextPageToken) break;
203				nextPageToken = response.nextPageToken;
204			}
205		}
206	
207		private async storeChangelogs({
208			installationDbId,
209			issues,
210			savedIssues,
211		}: {
212			installationDbId: string;
213			issues: IJiraApiIssue[];
214			savedIssues: IJiraIssueBase[];
215		}): Promise<void> {
216			const issueDbIdMap = new Map(savedIssues.map((i) => [i.issue_id, i._id]));
217			const entries: {
218				issue_id: string;
219				installation_id: string;
220				jira_history_id: string;
221				author_id: string | null;
222				field: string;
223				from_value: string | null;
224				to_value: string | null;
225				changed_at: Date;
226			}[] = [];
227	
228			for (const issue of issues) {
229				const issueDbId = issueDbIdMap.get(issue.id);
230				if (!issueDbId || !issue.changelog) continue;
231	
232				for (const history of issue.changelog.histories) {
233					for (const item of history.items) {
234						entries.push({
235							issue_id: issueDbId,
236							installation_id: installationDbId,
237							jira_history_id: history.id,
238							author_id: history.author?.accountId ?? null,
239							field: item.field,
240							from_value: item.fromString,
241							to_value: item.toString,
242							changed_at: new Date(history.created),
243						});
244					}
245				}
246			}
247	
248			await this.changelogModel.upsertMany({ entries });
249		}
250	
251		private async storeWorklogs({
252			installationDbId,
253			cloudId,
254			token,
255			issues,
256			savedIssues,
257		}: {
258			installationDbId: string;
259			cloudId: string;
260			token: string;
261			issues: IJiraApiIssue[];
262			savedIssues: IJiraIssueBase[];
263		}): Promise<void> {
264			const issueDbIdMap = new Map(savedIssues.map((i) => [i.issue_id, i._id]));
265	
266			for (const issue of issues) {
267				const issueDbId = issueDbIdMap.get(issue.id);
268				if (!issueDbId) continue;
269	
270				const worklogs = await this.jiraApiService.getWorklogsForIssue({
271					cloudId,
272					token,
273					issueId: issue.id,
274				});
275	
276				if (worklogs.length === 0) continue;
277	
278				await this.worklogModel.upsertMany({
279					worklogs: worklogs.map((w) => ({
280						issue_id: issueDbId,
281						installation_id: installationDbId,
282						jira_worklog_id: w.id,
283						author_id: w.author?.accountId ?? null,
284						time_spent_sec: w.timeSpentSeconds,
285						started_at: w.started ? new Date(w.started) : null,
286						updated_at: new Date(w.updated),
287					})),
288				});
289			}
290		}
291	
292		private async fetchAndStoreSprints({
293			installationDbId,
294			projectKey,
295			cloudId,
296			token,
297		}: {
298			installationDbId: string;
299			projectKey: string;
300			cloudId: string;
301			token: string;
302		}): Promise<void> {
303			try {
304				const boardsResponse = await this.jiraApiService.listBoards({
305					cloudId,
306					token,
307					projectKeyOrId: projectKey,
308				});
309	
310				for (const board of boardsResponse.values) {
311					let startAt = 0;
312					while (true) {
313						const sprintResponse = await this.jiraApiService.listSprints({
314							cloudId,
315							token,
316							boardId: board.id,
317							startAt,
318						});
319	
320						await this.sprintModel.upsertMany({
321							installationId: installationDbId,
322							boardId: String(board.id),
323							sprints: sprintResponse.values,
324						});
325	
326						if (sprintResponse.values.length === 0 || sprintResponse.isLast) break;
327						startAt += 50;
328					}
329				}
330			} catch (error) {
331				this.logger.warn(
332					`Failed to fetch sprints for project ${projectKey}: ${(error as Error).message}`,
333				);
334			}
335		}
336	}
