1037		async process({ name, data }: Job<IRawEventJob>): Promise<void> {
1038			if (name !== 'raw_event') return;
1039	
1040			const { event, installationId, payload } = data;
1041	
1042			const installation = await this.installationModel.findByInstallationId({ installationId });
1043			if (!installation) {
1044				this.logger.warn(`Processor: unknown installation ${installationId}, skipping`);
1045				return;
1046			}
1047	
1048			try {
1049				switch (event) {
1050					case 'push':
1051						await this.handlePush({
1052							installationDbId: installation._id,
1053							payload: payload as IGithubWebhookPushEvent,
1054						});
1055						break;
1056					case 'pull_request':
1057						await this.handlePullRequest({
1058							installationDbId: installation._id,
1059							payload: payload as IGithubWebhookPREvent,
1060						});
1061						break;
1062					case 'pull_request_review':
1063						await this.handleReview({
1064							installationDbId: installation._id,
1065							payload: payload as IGithubWebhookReviewEvent,
1066						});
1067						break;
1068					case 'pull_request_review_comment':
1069						await this.handleReviewComment({
1070							installationDbId: installation._id,
1071							payload: payload as IGithubWebhookReviewCommentEvent,
1072						});
1073						break;
1074					case 'installation_repositories':
1075						await this.handleInstallationRepositories({
1076							installationDbId: installation._id,
1077							installationId,
1078							payload: payload as IGithubInstallationRepositoriesEvent,
1079						});
1080						break;
1081					default:
1082						this.logger.debug(`Unhandled event type: ${event}`);
1083				}
1084			} catch (error) {
1085				this.logger.error(`Failed to process ${event} for installation ${installationId}: ${(error as Error).message}`);
1086				throw error;
1087			}
1088		}
