1090		private async handlePush({
1091			installationDbId,
1092			payload,
1093		}: {
1094			installationDbId: string;
1095			payload: IGithubWebhookPushEvent;
1096		}): Promise<void> {
1097			const repo = await this.repoModel.findByGithubRepoId({ githubRepoId: payload.repository.id });
1098			if (!repo) {
1099				this.logger.warn(`Repo not found for github_repo_id ${payload.repository.id}`);
1100				return;
1101			}
1102	
1103			const commits = payload.commits.filter((c) => c.distinct);
1104			if (commits.length === 0) return;
1105	
1106			for (const commit of commits) {
1107				if (commit.author.username) {
1108					await this.contributorModel.upsert({
1109						data: {
1110							installation_id: installationDbId,
1111							github_user_id: 0,
1112							github_login: commit.author.username,
1113							github_name: commit.author.name,
1114							github_email: commit.author.email,
1115						},
1116					});
1117				}
1118			}
1119	
1120			await this.commitModel.upsertMany({
1121				commits: commits.map((c) => ({
1122					installation_id: installationDbId,
1123					repo_id: repo._id,
1124					sha: c.id,
1125					message: c.message,
1126					author_login: c.author.username ?? null,
1127					author_name: c.author.name,
1128					author_email: c.author.email,
1129					committed_at: new Date(c.timestamp),
1130					additions: 0,
1131					deletions: 0,
1132					is_merge_commit: (c.parents?.length ?? 0) > 1,
1133				})),
1134			});
1135	
1136			this.logger.debug(`Processed push: ${commits.length} commits for repo ${repo.full_name}`);
1137		}
